            original += (long long)prefix_L[j] * suffix_T[j + 1];
        }
    }
    long long max_L = 0;
    for (int i = 0; i <= n; ++i) {
        long long val = (long long)suffix_C[i] * suffix_T[i];
        if (val > max_L) max_L = val;
    }
    long long max_C = 0;
    for (int i = 0; i <= n; ++i) {
        long long val = (long long)prefix_L[i] * suffix_T[i];
        if (val > max_C) max_C = val;
    }
    long long max_T = 0;
    for (int i = 0; i <= n; ++i) {
        long long val = (long long)prefix_L[i] * prefix_C[i];
        if (val > max_T) max_T = val;
    }
    return original + max(max_L, max_C, max_T);
}

